import * as d3 from "d3";

function draw_bar (rect, maxValue) {
  rect.attr("fill", "steelblue")
    .attr("x", function(d, i){
      return 40 + i * 35
    })
    .attr("y", function(d){
      // top of the bar = SVG height 500 - bottom pad 20 - bar height
      return 480 - 460 * (d.counts / maxValue);
    })
    .attr("width", 32)
    .attr("height", function(d){
      // largest bar height = SVG height 500 - bottom & top pad (20+20)
      // every bar height = largest bar height * ratio to the highest bar
      return 460 * (d.counts / maxValue);
    });
}

