const V = 458; // square virtual size
const presets = {
  top:   [200,  25, 350], // top marginal center & needed square width
  right: [433, 258, 350], // right marginal center & needed square width
  full:  [229, 229, 458], // full canvas
};

// Convert preset to CSS translate/scale that keeps (cx,cy) at the viewport center
function presetToCSS([cx, cy, width], V) {
  const k  = V / width;             // scale
  const tx = V / 2 - k * cx;        // translate x in px
  const ty = V / 2 - k * cy;        // translate y in px
  return { k, tx, ty };
}

const canvas = document.getElementById('canvas');

// Apply a view to the whole grid
function applyView(name) {
  const { k, tx, ty } = presetToCSS(presets[name], V);
  canvas.style.transition = 'transform 0.8s ease-in-out';
  canvas.style.transform  = `translate(${tx}px, ${ty}px) scale(${k})`;
}

// Keys: 1 → top, 2 → right, Esc → full
window.addEventListener('keydown', (e) => {
  if (e.key === '1') {
    applyView('top');
  } else if (e.key === '2') {
    applyView('right');
  } else if (e.key === 'Escape') {
    applyView('full');
  }
});

// Optional: start at full view
